	@Test
	void createStoreConfigBudgetsOptimizerSamplingToHalfQueryTimeout() throws Exception {
		ThemeQueryPlanRunBenchmark.BaseState state = new ThemeQueryPlanRunBenchmark.BaseState();
		state.sketchEstimatorEnabled = true;
		state.sketchEstimatorStrategy = "omni";
		Method method = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredMethod("createStoreConfig");
		method.setAccessible(true);

		LmdbStoreConfig config = (LmdbStoreConfig) method.invoke(state);

		assertEquals(30_000L, config.getOptimizerSamplingMaxMillis());
	}

	@Test
	void trialTeardownPrintsTelemetryPlan() throws Exception {
		ThemeQueryPlanRunBenchmark.ExecutionState state = new ThemeQueryPlanRunBenchmark.ExecutionState();
		state.themeName = Theme.MEDICAL_RECORDS.name();
		state.z_queryIndex = 0;
		state.sketchEstimatorEnabled = false;
		state.sketchEstimatorStrategy = "fastagms";
		state.query = "SELECT * WHERE { ?s ?p ?o }";
		setTheme(state, Theme.MEDICAL_RECORDS);

		SailRepository repository = new SailRepository(
				new LmdbStore(new File(tempDir.toFile(), "store"), ConfigUtil.createConfig()));
		PrintStream previousOut = System.out;
		ByteArrayOutputStream out = new ByteArrayOutputStream();

		try {
			state.connection = repository.getConnection();
			System.setOut(new PrintStream(out, true, StandardCharsets.UTF_8));

			state.tearDown();

			String output = out.toString(StandardCharsets.UTF_8);
			int telemetryIndex = output.indexOf("### Telemetry Query - Trial teardown ###");
			int renderedIndex = output.indexOf("### Rendered Optimized SPARQL - Trial teardown ###");
			assertTrue(telemetryIndex >= 0, output);
			assertTrue(renderedIndex > telemetryIndex, output);
			assertTrue(output.substring(renderedIndex).contains("SELECT"), output);
			assertTrue(output.contains("Rendered optimized SPARQL file:"), output);
			String renderedFilePath = output.lines()
					.filter(line -> line.startsWith("Rendered optimized SPARQL file:"))
					.map(line -> line.substring("Rendered optimized SPARQL file:".length()).trim())
					.findFirst()
					.orElseThrow();
			File renderedFile = new File(renderedFilePath);
			assertTrue(renderedFile.isFile(), "Expected rendered SPARQL file: " + renderedFile + "\n" + output);
			assertTrue(java.nio.file.Files.readString(renderedFile.toPath()).contains("SELECT"));
		} finally {
			System.setOut(previousOut);
			if (state.connection != null) {
				state.connection.close();
			}
			repository.shutDown();
		}
	}

	@Test
	void trialTeardownSkipsTelemetryPlanWhileProfiling() throws Exception {
		ThemeQueryPlanRunBenchmark.ExecutionState state = new ThemeQueryPlanRunBenchmark.ExecutionState();
		state.themeName = Theme.MEDICAL_RECORDS.name();
		state.z_queryIndex = 0;
		state.sketchEstimatorEnabled = false;
		state.sketchEstimatorStrategy = "fastagms";
		state.query = "SELECT * WHERE { ?s ?p ?o }";
		setTheme(state, Theme.MEDICAL_RECORDS);

		SailRepository repository = new SailRepository(
				new LmdbStore(new File(tempDir.toFile(), "profiling-store"), ConfigUtil.createConfig()));
		PrintStream previousOut = System.out;
		String previousProfiling = System.getProperty(PROFILING_PROPERTY);
		ByteArrayOutputStream out = new ByteArrayOutputStream();

		try {
			state.connection = repository.getConnection();
			System.setOut(new PrintStream(out, true, StandardCharsets.UTF_8));
			System.setProperty(PROFILING_PROPERTY, "true");

			state.tearDown();

			assertEquals("", out.toString(StandardCharsets.UTF_8));
		} finally {
			if (previousProfiling == null) {
				System.clearProperty(PROFILING_PROPERTY);
			} else {
				System.setProperty(PROFILING_PROPERTY, previousProfiling);
			}
			System.setOut(previousOut);
			if (state.connection != null) {
				state.connection.close();
			}
			repository.shutDown();
		}
	}

	@Test
	void medicalQ7ValuesVariantForcesFiniteCodeAnchorQuery() throws Exception {
		Method method = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredMethod("queryForVariant", Theme.class,
				int.class, String.class);
		method.setAccessible(true);

		String query = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "medical-q7-values");

		assertTrue(query.contains("VALUES ?code { \"MED-1000\" \"MED-1001\" }"), query);
		assertFalse(query.contains("FILTER(?code = \"MED-1000\" || ?code = \"MED-1001\")"), query);
		assertTrue(query.contains("MINUS"), query);
	}

	@Test
	void medicalQ7FilterInVariantUsesEquivalentFiniteFilterSyntax() throws Exception {
		Method method = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredMethod("queryForVariant", Theme.class,
				int.class, String.class);
		method.setAccessible(true);

		String query = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "filter-in");

		assertTrue(query.contains("FILTER(?code IN (\"MED-1000\", \"MED-1001\"))"), query);
		assertFalse(query.contains("VALUES ?code { \"MED-1000\" \"MED-1001\" }"), query);
		assertTrue(query.contains("MINUS"), query);
	}

	@Test
	void medicalQ7PlacementVariantsRenderRequestedInputOrder() throws Exception {
		Method method = ThemeQueryPlanRunBenchmark.BaseState.class.getDeclaredMethod("queryForVariant", Theme.class,
				int.class, String.class);
		method.setAccessible(true);

		String valuesTop = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "values-top-type-code");
		String typeFirst = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "type-values-code");
		String codeFirst = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "values-code-type");
		String antiBeforeValues = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "type-anti-values-code");
		String codeAntiBeforeType = (String) method.invoke(null, Theme.MEDICAL_RECORDS, 7, "values-code-anti-type");

		assertOrder(valuesTop, "VALUES ?code", "?med a med:Medication", "?med med:code ?code");
		assertOrder(typeFirst, "?med a med:Medication", "VALUES ?code", "?med med:code ?code");
		assertOrder(codeFirst, "VALUES ?code", "?med med:code ?code", "?med a med:Medication");
		assertOrder(antiBeforeValues, "?med a med:Medication", "FILTER NOT EXISTS", "VALUES ?code");
		assertOrder(antiBeforeValues, "FILTER NOT EXISTS", "VALUES ?code", "?med med:code ?code");
		assertOrder(codeAntiBeforeType, "VALUES ?code", "?med med:code ?code", "FILTER NOT EXISTS");
		assertOrder(codeAntiBeforeType, "FILTER NOT EXISTS", "?med a med:Medication", "FILTER EXISTS");
	}

